1	<!DOCTYPE html>
2	<html lang="zh-CN">
3	<head>
4	    <meta charset="UTF-8">
5	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	    <title>saveole's land</title>
7	    <link rel="icon" type="image/x-icon" href="./assets/img/favicons/favicon.ico">
8	    <link rel="icon" type="image/png" sizes="32x32" href="./assets/img/favicons/favicon-32x32.png">
9	    <link rel="icon" type="image/png" sizes="16x16" href="./assets/img/favicons/favicon-16x16.png">
10	    <link rel="apple-touch-icon" sizes="180x180" href="./assets/img/favicons/apple-touch-icon.png">
11	    <link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600&family=Source+Serif+Pro:ital,wght@0,400;0,700;1,400&display=swap">
12	    <link rel="stylesheet" href="style.css">
13	</head>
14	<body>
15	    <nav class="navbar">
16	        <div class="container navbar-inner">
17	            <a href="index.html" class="logo">Blog.</a>
18	            <a href="running.html" class="nav-link">Running</a>
19	            <a href="reading.html" class="nav-link">Reading</a>
20	        </div>
21	    </nav>
22	
23	    <main class="container">
24	        <header class="home-header">
25	            <p class="contrib-title">Token 不够？<a href="running.html">跑步</a>来凑！ <span class="contrib-summary" id="contrib-summary"></span></p>
26	            <div class="contrib-wrapper">
27	                <div class="contrib-months" id="contrib-months"></div>
28	                <div class="contrib-body">
29	                    <div class="contrib-days">
30	                        <span>Mon</span><span>Wed</span><span>Fri</span>
31	                    </div>
32	                    <div class="contrib-grid" id="contrib-grid"></div>
33	                </div>
34	            </div>
35	            <div class="contrib-legend">
36	                <div class="legend-group">
37	                    <span class="legend-label">🏃 Less</span>
38	                    <span class="legend-cell run-0"></span>
39	                    <span class="legend-cell run-1"></span>
40	                    <span class="legend-cell run-2"></span>
41	                    <span class="legend-cell run-3"></span>
42	                    <span class="legend-cell run-4"></span>
43	                    <span class="legend-cell run-5"></span>
44	                    <span class="legend-label">More</span>
45	                </div>
46	                <span class="legend-divider"></span>
47	                <div class="legend-group">
48	                    <span class="legend-label">💻 Less</span>
49	                    <span class="legend-cell token-0"></span>
50	                    <span class="legend-cell token-1"></span>
51	                    <span class="legend-cell token-2"></span>
52	                    <span class="legend-cell token-3"></span>
53	                    <span class="legend-cell token-4"></span>
54	                    <span class="legend-label">More</span>
55	                </div>
56	                <span class="legend-info-btn" tabindex="0">&#9432;</span>
57	                <div class="legend-info-panel">
58	                    <p><strong>Token 统计</strong>：仅统计 <strong>Claude Code</strong> 和 <strong>Hermes</strong> 的 token 消耗，不包含其他 AI 工具或平台。每个会话结束时，按 <code>session_id</code> 记录总消耗，归入<strong>会话结束当日</strong>（UTC）。</p>
59	                    <p><strong>跑步数据</strong>：来自 Garmin Connect CN，颜色基准 5km。</p>
60	                    <p><strong>可能的误差</strong>：</p>
61	                    <ul>
62	                        <li>跨天会话的所有 token 均计入结束日，开始日数据会偏低</li>
63	                        <li>使用 <code>--resume</code> 恢复会话后，transcript 为全量，可能导致旧 token 被重复计入新日期</li>
64	                    </ul>
65	                    <p class="legend-info-note">以上场景实际发生频率较低，不影响整体趋势参考。</p>
66	                </div>
67	            </div>
68	        </header>
69	
70	        <section class="post-list">
71	            <% posts.forEach(post => { %>
72	                <div class="post-item" >
73	                    <time>
74	                        <%= post.date %>
75	                    </time>
76	                    <h2>
77	                        <a href="<%= post.url %>" style="text-decoration: none; color: var(--text-main);"><%= post.title %></a>
78	                    </h2>
79	                    <% if (post.subtitle) { %>
80	                        <p></p>
81	                    <% } %>
82	                </div>
83	            <% }) %>
84	        </section>
85	    </main>
86	
87	    <footer class="container">
88	        <p>&copy; 2026 saveole.</p>
89	    </footer>
90	
91	    <script>
92	    (function() {
93	        var data = <%- dailyData %>;
94	        if (!data || !data.days || data.days.length === 0) return;
95	
96	        var tokenMap = {};
97	        var runningMap = {};
98	        data.days.forEach(function(d) {
99	            if (d.total_tokens) {
100	                var t = d.total_tokens;
101	                tokenMap[d.date] = t.input + t.output + t.cache_read + t.cache_creation;
102	            }
103	            if (d.running_km) runningMap[d.date] = d.running_km;
104	        });
105	
106	        var today = new Date();
107	        var todayStr = today.getFullYear() + '-' +
108	            String(today.getMonth() + 1).padStart(2, '0') + '-' +
109	            String(today.getDate()).padStart(2, '0');
110	
111	        var oneYearAgo = new Date(today);
112	        oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);
113	        var dayOfWeek = oneYearAgo.getDay();
114	        var mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
115	        var startDate = new Date(oneYearAgo);
116	        startDate.setDate(startDate.getDate() + mondayOffset);
117	
118	        var weeks = [];
119	        var monthLabels = [];
120	        var lastMonth = -1;
121	
122	        function toDateStr(d) {
123	            return d.getFullYear() + '-' +
124	                String(d.getMonth() + 1).padStart(2, '0') + '-' +
125	                String(d.getDate()).padStart(2, '0');
126	        }
127	
128	        while (toDateStr(startDate) <= todayStr) {
129	            var week = [];
130	            for (var i = 0; i < 7; i++) {
131	                var dateStr = toDateStr(startDate);
132	                var month = startDate.getMonth();
133	                if (i === 0 && month !== lastMonth) {
134	                    monthLabels.push({
135	                        month: startDate.toLocaleString('zh-CN', { month: 'short' }),
136	                        weekIndex: weeks.length
137	                    });
138	                    lastMonth = month;
139	                }
140	                week.push({
141	                    date: dateStr,
142	                    tokens: tokenMap[dateStr] || 0,
143	                    running: runningMap[dateStr] || 0,
144	                    future: dateStr > todayStr
145	                });
146	                startDate.setDate(startDate.getDate() + 1);
147	            }
148	            weeks.push(week);
149	        }
150	
151	        // Token color levels (quartile-based, all data)
152	        var tokenValues = Object.values(tokenMap).filter(function(v) { return v > 0; }).sort(function(a, b) { return a - b; });
153	        function getQuantile(arr, q) {
154	            var pos = (arr.length - 1) * q;
155	            var base = Math.floor(pos);
156	            var rest = pos - base;
157	            if (arr[base + 1] !== undefined) return arr[base] + rest * (arr[base + 1] - arr[base]);
158	            return arr[base];
159	        }
160	        var q1 = tokenValues.length > 0 ? getQuantile(tokenValues, 0.25) : 0;
161	        var q2 = tokenValues.length > 0 ? getQuantile(tokenValues, 0.5) : 0;
162	        var q3 = tokenValues.length > 0 ? getQuantile(tokenValues, 0.75) : 0;
163	
164	        function getTokenLevel(v) {
165	            if (v === 0) return 0;
166	            if (v <= q1) return 1;
167	            if (v <= q2) return 2;
168	            if (v <= q3) return 3;
169	            return 4;
170	        }
171	
172	        function getRunLevel(km) {
173	            if (km <= 0) return 0;
174	            if (km < 3) return 1;
175	            if (km < 5) return 2;
176	            if (km < 10) return 3;
177	            if (km < 15) return 4;
178	            return 5;
179	        }
180	
181	        function formatRunning(km) {
182	            return km < 10 ? km.toFixed(1) : km.toFixed(0);
183	        }
184	
185	        function formatTokens(n) {
186	            if (n >= 1e6) return (n / 1e6).toFixed(1) + ' M';
187	            if (n >= 1e3) {
188	                var k = n / 1e3;
189	                return (k >= 100 ? k.toFixed(0) : k.toFixed(1)) + ' K';
190	            }
191	            return String(n);
192	        }
193	
194	        // Render month labels
195	        var monthsEl = document.getElementById('contrib-months');
196	        var monthHtml = '';
197	        var prevWeekIdx = -10;
198	        monthLabels.forEach(function(m) {
199	            var offset = m.weekIndex * 14;
200	            if (m.weekIndex > prevWeekIdx + 3) {
201	                monthHtml += '<span style="position:absolute;left:' + offset + 'px">' + m.month + '</span>';
202	                prevWeekIdx = m.weekIndex;
203	            }
204	        });
205	        monthsEl.innerHTML = monthHtml;
206	
207	        // Render grid
208	        var totalWeeks = weeks.length;
209	        var edgeCount = 8;
210	        var gridEl = document.getElementById('contrib-grid');
211	        var gridHtml = '';
212	
213	        weeks.forEach(function(week, wi) {
214	            week.forEach(function(day, di) {
215	                if (day.future) {
216	                    gridHtml += '<span class="contrib-cell" data-date="' + day.date + '" style="grid-column:' + (wi + 1) + ';grid-row:' + (di + 1) + '"></span>';
217	                    return;
218	                }
219	
220	                var hasRun = day.running > 0;
221	                var hasTok = day.tokens > 0;
222	                var runLvl = getRunLevel(day.running);
223	                var tokLvl = getTokenLevel(day.tokens);
224	
225	                var bg;
226	                if (hasRun && hasTok) {
227	                    bg = 'background:linear-gradient(90deg,var(--run-' + runLvl + ') 50%,var(--token-' + tokLvl + ') 50%)';
228	                } else if (hasRun) {
229	                    bg = 'background:var(--run-' + runLvl + ')';
230	                } else if (hasTok) {
231	                    bg = 'background:var(--token-' + tokLvl + ')';
232	                } else {
233	                    bg = 'background:var(--empty-cell)';
234	                }
235	
236	                var cls = 'contrib-cell';
237	                if (wi < edgeCount) cls += ' edge-left';
238	                if (wi >= totalWeeks - edgeCount) cls += ' edge-right';
239	
240	                var runStr = (hasRun ? formatRunning(day.running) : '0') + ' km';
241	                var tokStr = hasTok ? formatTokens(day.tokens) : '0 M';
242	                var tooltip = day.date + '\n🏃 ' + runStr + '\n💻 ' + tokStr;
243	
244	                gridHtml += '<span class="' + cls + '" data-date="' + day.date + '" data-tooltip="' + tooltip + '" style="' + bg + ';grid-column:' + (wi + 1) + ';grid-row:' + (di + 1) + '"></span>';
245	            });
246	        });
247	        gridEl.innerHTML = gridHtml;
248	
249	        // Summary statistics
250	        var totalTokens = 0, totalRunning = 0, activeDays = 0;
251	        weeks.forEach(function(week) {
252	            week.forEach(function(day) {
253	                if (day.future) return;
254	                if (day.tokens > 0) { totalTokens += day.tokens; }
255	                if (day.running > 0) { totalRunning += day.running; }
256	                if (day.tokens > 0 || day.running > 0) { activeDays++; }
257	            });
258	        });
259	        var summaryParts = [];
260	        if (totalTokens > 0) summaryParts.push(formatTokens(totalTokens) + ' tokens');
261	        if (totalRunning > 0) summaryParts.push(totalRunning.toFixed(0) + ' km');
262	        if (activeDays > 0) summaryParts.push(activeDays + ' 天活跃');
263	        var summaryEl = document.getElementById('contrib-summary');
264	        if (summaryEl && summaryParts.length > 0) {
265	            summaryEl.textContent = '· ' + summaryParts.join(' · ');
266	        }
267	
268	        // Info panel click toggle (touch-friendly)
269	        var infoBtn = document.querySelector('.legend-info-btn');
270	        var infoPanel = document.querySelector('.legend-info-panel');
271	        if (infoBtn && infoPanel) {
272	            infoBtn.addEventListener('click', function(e) {
273	                e.stopPropagation();
274	                infoPanel.classList.toggle('active');
275	            });
276	            document.addEventListener('click', function(e) {
277	                if (!infoPanel.contains(e.target) && e.target !== infoBtn) {
278	                    infoPanel.classList.remove('active');
279	                }
280	            });
281	        }
282	    })();
283	    </script>
284	</body>
285	</html>

1	:root {
2	  --bg-color: #f8f9fa;
3	  --text-main: #1a202c;
4	  --text-muted: #64748b;
5	  --primary-color: #2563eb;
6	  --border-color: #e5e7eb;
7	  --code-bg: #f3f4f6;
8	  --code-color: #1a202c;
9	  --content-width: 840px;
10	  --run-0: #ebedf0;
11	  --run-1: #86efac;
12	  --run-2: #fde047;
13	  --run-3: #fb923c;
14	  --run-4: #ef4444;
15	  --run-5: #b91c1c;
16	  --token-0: #ebedf0;
17	  --token-1: #c6e0ff;
18	  --token-2: #7db8ff;
19	  --token-3: #3b8aff;
20	  --token-4: #2563eb;
21	  --empty-cell: #ebedf0;
22	}
23	
24	/* 基础重置 */
25	* {
26	  box-sizing: border-box;
27	  margin: 0;
28	  padding: 0;
29	}
30	
31	body {
32	  background-color: var(--bg-color);
33	  color: var(--text-main);
34	  font-family: "Source Serif Pro", serif;
35	  line-height: 1.8;
36	}
37	
38	/* 居中核心：container */
39	.container {
40	  max-width: var(--content-width);
41	  margin: 0 auto; /* 水平居中 */
42	  padding: 0 1.5rem;
43	}
44	
45	/* 导航和页脚居中 */
46	.navbar,
47	footer {
48	  width: 100%;
49	  padding: 2rem 0;
50	}
51	
52	.navbar-inner {
53	  display: flex;
54	  justify-content: space-between;
55	  align-items: center;
56	}
57	
58	.nav-link {
59	  font-family: "Inter", sans-serif;
60	  font-size: 0.82rem;
61	  color: var(--text-muted);
62	  text-decoration: none;
63	  letter-spacing: 0.2px;
64	  position: relative;
65	  padding-bottom: 2px;
66	  transition: color 0.25s ease;
67	}
68	
69	.nav-link::after {
70	  content: "";
71	  position: absolute;
72	  bottom: 0;
73	  left: 0;
74	  width: 0;
75	  height: 1px;
76	  background: var(--primary-color);
77	  transition: width 0.3s ease;
78	}
79	
80	.nav-link:hover {
81	  color: var(--text-main);
82	}
83	
84	.nav-link:hover::after {
85	  width: 100%;
86	}
87	
88	.post {
89	  margin-top: 4rem;
90	}
91	
92	/* Post header meta (categories + tags) */
93	.post-meta {
94	  display: flex;
95	  align-items: center;
96	  gap: 0.75rem;
97	  margin-top: 0.6rem;
98	  flex-wrap: wrap;
99	}
100	
101	.post-categories {
102	  font-family: "Inter", sans-serif;
103	  font-size: 0.78rem;
104	  color: var(--text-muted);
105	}
106	
107	.post-tags {
108	  display: flex;
109	  flex-wrap: wrap;
110	  gap: 0.35rem;
111	}
112	
113	.post-header-tag {
114	  font-family: "Inter", sans-serif;
115	  font-size: 0.75rem;
116	  font-weight: 500;
117	  color: var(--primary-color);
118	  background: color-mix(in srgb, var(--primary-color) 8%, transparent);
119	  border: 1px solid color-mix(in srgb, var(--primary-color) 15%, transparent);
120	  padding: 1px 8px;
121	  border-radius: 4px;
122	  text-decoration: none;
123	  cursor: pointer;
124	  transition: background 0.2s;
125	}
126	
127	.post-header-tag:hover {
128	  background: color-mix(in srgb, var(--primary-color) 16%, transparent);
129	}
130	
131	.post-content p {
132	  margin-bottom: 1.5rem;
133	}
134	
135	/* ====== 代码块样式 - 与博客主题统一 ====== */
136	
137	/* 行内代码 */
138	code {
139	  background: var(--code-bg);
140	  color: var(--code-color);
141	  padding: 0.2em 0.4em;
142	  border-radius: 4px;
143	  font-family: "JetBrains Mono", "Courier New", monospace;
144	  font-size: 0.88em;
145	}
146	
147	/* 代码块容器 */
148	pre {
149	  background: var(--code-bg);
150	  color: var(--code-color);
151	  padding: 1.5rem;
152	  border-radius: 8px;
153	  overflow-x: auto;
154	  margin: 2rem 0;
155	  font-family: "JetBrains Mono", "Courier New", monospace;
156	  font-size: 0.9rem;
157	  line-height: 1.5;
158	  border: 1px solid var(--border-color);
159	}
160	
161	/* pre 内的 code 不重复加背景和 padding */
162	pre code {
163	  background: transparent;
164	  color: inherit;
165	  padding: 0;
166	  border-radius: 0;
167	  font-size: inherit;
168	}
169	
170	/* ====== Highlight.js 北欧风配色 (浅色主题) ====== */
171	.hljs {
172	  color: var(--text-main);
173	}
174	
175	.hljs-keyword,
176	.hljs-selector-tag,
177	.hljs-literal {
178	  color: #2563eb;
179	  font-weight: bold;
180	}
181	
182	.hljs-string,
183	.hljs-addition,
184	.hljs-regexp,
185	.hljs-attr {
186	  color: #059669;
187	}
188	
189	.hljs-comment,
190	.hljs-quote,
191	.hljs-meta .hljs-meta-string,
192	.hljs-doctag {
193	  color: #94a3b8;
194	  font-style: italic;
195	}
196	
197	.hljs-number,
198	.hljs-built_in,
199	.hljs-type,
200	.hljs-template-variable,
201	.hljs-tag .hljs-attr {
202	  color: #d97706;
203	}
204	
205	.hljs-title,
206	.hljs-function,
207	.hljs-title.class_,
208	.hljs-section {
209	  color: #7c3aed;
210	}
211	
212	.hljs-attr,
213	.hljs-attribute,
214	.hljs-variable {
215	  color: #9333ea;
216	}
217	
218	.hljs-symbol,
219	.hljs-bullet,
220	.hljs-link,
221	.hljs-subst {
222	  color: #0891b2;
223	}
224	
225	.hljs-deletion {
226	  color: #dc2626;
227	  background: rgba(220, 38, 38, 0.08);
228	}
229	
230	.hljs-meta {
231	  color: #64748b;
232	}
233	
234	.hljs-emphasis {
235	  font-style: italic;
236	}
237	.hljs-strong {
238	  font-weight: bold;
239	}
240	
241	/* ====== 暗色模式代码块 ====== */
242	@media (prefers-color-scheme: dark) {
243	  :root {
244	    --bg-color: #0f172a;
245	    --text-main: #e2e8f0;
246	    --text-muted: #94a3b8;
247	    --primary-color: #60a5fa;
248	    --border-color: #1e293b;
249	    --code-bg: #1e293b;
250	    --code-color: #e2e8f0;
251	    --run-0: #161b22;
252	    --run-1: #16a34a;
253	    --run-2: #ca8a04;
254	    --run-3: #ea580c;
255	    --run-4: #dc2626;
256	    --run-5: #7f1d1d;
257	    --token-0: #161b22;
258	    --token-1: #1d4ed8;
259	    --token-2: #2563eb;
260	    --token-3: #3b82f6;
261	    --token-4: #60a5fa;
262	    --empty-cell: #161b22;
263	  }
264	
265	  pre {
266	    border-color: #334155;
267	  }
268	
269	  .hljs {
270	    color: #e2e8f0;
271	  }
272	
273	  .hljs-keyword,
274	  .hljs-selector-tag,
275	  .hljs-literal {
276	    color: #93c5fd;
277	  }
278	
279	  .hljs-string,
280	  .hljs-addition,
281	  .hljs-regexp,
282	  .hljs-attr {
283	    color: #6ee7b7;
284	  }
285	
286	  .hljs-comment,
287	  .hljs-quote {
288	    color: #64748b;
289	  }
290	
291	  .hljs-number,
292	  .hljs-built_in,
293	  .hljs-type,
294	  .hljs-template-variable {
295	    color: #fcd34d;
296	  }
297	
298	  .hljs-title,
299	  .hljs-function,
300	  .hljs-title.class_,
301	  .hljs-section {
302	    color: #c4b5fd;
303	  }
304	
305	  .hljs-attr,
306	  .hljs-attribute,
307	  .hljs-variable {
308	    color: #f0abfc;
309	  }
310	
311	  .hljs-symbol,
312	  .hljs-bullet,
313	  .hljs-link,
314	  .hljs-subst {
315	    color: #67e8f9;
316	  }
317	
318	  .hljs-deletion {
319	    color: #fca5a5;
320	    background: rgba(239, 68, 68, 0.15);
321	  }
322	
323	  .contrib-cell[data-tooltip]:hover::after {
324	    background: rgba(30, 41, 59, 0.75);
325	    border-color: #334155;
326	  }
327	}
328	
329	/* ============ Running Page ============ */
330	
331	.running-header {
332	  margin: 4rem 0 2rem;
333	}
334	
335	.running-header h1 {
336	  font-size: 1.5rem;
337	  font-weight: 300;
338	  letter-spacing: -0.5px;
339	  margin: 0 0 0.3rem;
340	  color: var(--text-main);
341	}
342	
343	.running-header p {
344	  color: var(--text-muted);
345	  font-family: "Inter", sans-serif;
346	  font-size: 0.82rem;
347	  margin: 0;
348	}
349	
